import { MakeLogicType, actions, connect, kea, key, path, props, reducers } from 'kea'

import { entityFilterLogic } from 'scenes/insights/filters/ActionFilter/entityFilterLogic'
import { getDisplayNameFromEntityFilter } from 'scenes/insights/utils'

import { EntityFilterTypes } from '~/types'

import type { ActionFilter, EntityFilter } from '../../../../types'

export interface RenameModalProps {
    filter: EntityFilterTypes
    typeKey: string
}

// Generated by kea-typegen. Update if you're an agent, ignore if you're human.
export interface renameModalLogicValues {
    name: string
}

// Generated by kea-typegen. Update if you're an agent, ignore if you're human.
export interface renameModalLogicActions {
    selectFilter: (filter: ActionFilter | EntityFilter | null) => {
        filter: ActionFilter | EntityFilter | null
    } // entityFilterLogic
    setName: (name: string) => {
        name: string
    }
}

// Generated by kea-typegen. Update if you're an agent, ignore if you're human.
export interface renameModalLogicMeta {
    key: string
}

export type renameModalLogicType = MakeLogicType<
    renameModalLogicValues,
    renameModalLogicActions,
    RenameModalProps,
    renameModalLogicMeta
>

export const renameModalLogic = kea<renameModalLogicType>([
    props({} as RenameModalProps),
    key((props) => props.typeKey),
    path((key) => ['scenes', 'insights', 'ActionFilter', 'renameModalLogic', key]),
    connect((props: RenameModalProps) => ({
        actions: [entityFilterLogic({ typeKey: props.typeKey }), ['selectFilter']],
    })),
    actions(() => ({
        setName: (name: string) => ({ name }),
    })),
    reducers(({ props }) => ({
        name: [
            getDisplayNameFromEntityFilter(props.filter) ?? '',
            {
                setName: (_, { name }) => name,
                selectFilter: (_, { filter }) => getDisplayNameFromEntityFilter(filter) ?? '',
            },
        ],
    })),
])
